// ---------- paleta (tema CLARO, alto contraste) ----------
const C = {
  bg: "#FBFAF7", panel: "#FFFFFF", panel2: "#F4F2EC", line: "#E3DFD5",
  ink: "#191917", dim: "#56544D", faint: "#8C8A80",
  gold: "#B26A00", teal: "#197E6E", clay: "#BC3F22", blue: "#2F628F",
  goldBg: "rgba(178,106,0,0.10)", tealBg: "rgba(25,126,110,0.10)", clayBg: "rgba(188,63,34,0.10)",
};
const FS = "'Space Grotesk', ui-sans-serif, system-ui, sans-serif";
const FM = "'IBM Plex Mono', ui-monospace, 'SF Mono', monospace";

const SERIES = ["A", "B", "C", "D", "E", "F", "G", "H", "I", "J", "K", "L"];
const MONTHS = ["jan", "fev", "mar", "abr", "mai", "jun", "jul", "ago", "set", "out", "nov", "dez"];

const fmt = (x, d = 2) => (x === null || x === undefined || isNaN(x) ? "—" : Number(x).toFixed(d));
const pct = (x, d = 2) => (x === null || x === undefined || isNaN(x) ? "—" : (x * 100).toFixed(d) + "%");

// interpolação/extrapolação linear 1D
function interp1d(xs, ys, x) {
  if (!xs.length) return null;
  if (xs.length === 1) return ys[0];
  if (x <= xs[0]) { const s = (ys[1] - ys[0]) / (xs[1] - xs[0]); return ys[0] + s * (x - xs[0]); }
  const n = xs.length;
  if (x >= xs[n - 1]) { const s = (ys[n - 1] - ys[n - 2]) / (xs[n - 1] - xs[n - 2]); return ys[n - 1] + s * (x - xs[n - 1]); }
  for (let i = 0; i < n - 1; i++) if (x >= xs[i] && x <= xs[i + 1]) {
    const t = (x - xs[i]) / (xs[i + 1] - xs[i]); return ys[i] + t * (ys[i + 1] - ys[i]);
  }
  return ys[n - 1];
}
// P(toque) bilinear (osc × du), com extrapolação para fora das tabelas
function pToque(ativo, varFrac, dte) {
  const t = PROB[ativo];
  if (!t || varFrac == null || isNaN(varFrac)) return null;
  const oscPct = varFrac * 100;
  const keys = Object.keys(t.rows).map(Number).sort((a, b) => a - b);
  const perDu = t.du.map((_, ci) => {
    const xs = [], ys = [];
    keys.forEach((k) => { const val = t.rows[k.toFixed(1)][ci]; if (val != null) { xs.push(k); ys.push(val); } });
    return interp1d(xs, ys, oscPct);
  });
  const xs = [], ys = [];
  t.du.forEach((d, i) => { if (perDu[i] != null) { xs.push(d); ys.push(perDu[i]); } });
  let val = interp1d(xs, ys, dte);
  if (val == null) return null;
  val = Math.max(1, Math.min(99, val));
  const extr = oscPct > keys[keys.length - 1] || oscPct < keys[0] || dte < xs[0] || dte > xs[xs.length - 1];
  return { p: Math.round(val), extr };
}

function boxClass(bp) {
  if (bp < 0.05) return { tag: "curto", col: C.clay };
  if (bp < 0.075) return { tag: "OTM-M", col: C.teal };
  if (bp <= 0.10) return { tag: "OTM-L", col: C.gold };
  return { tag: "XL", col: C.clay };
}
function clInfo(cl) {
  if (cl < 0.45) return { t: "barato", col: C.teal };
  if (cl <= 0.55) return { t: "avaliar", col: C.gold };
  return { t: "caro", col: C.clay };
}

// núcleo de cálculo de uma operação
function computeOp(inp) {
  const s = +inp.S, box = +inp.box, asa = +inp.asa, dte = parseInt(inp.dte);
  if (!(s > 0 && box > 0 && asa > 0)) return null;
  const kCC = inp.kCC !== "" && inp.kCC != null ? +inp.kCC : s + box / 2;
  const kPC = inp.kPC !== "" && inp.kPC != null ? +inp.kPC : s - box / 2;
  const kCV = inp.kCV !== "" && inp.kCV != null ? +inp.kCV : s + box / 2 + asa;
  const kPV = inp.kPV !== "" && inp.kPV != null ? +inp.kPV : s - box / 2 - asa;
  const prices = [inp.pPV, inp.pPC, inp.pCC, inp.pCV];
  const hasPrices = prices.some((v) => v !== "" && v != null && !isNaN(+v));
  const debito = (+inp.pCC || 0) + (+inp.pPC || 0) - (+inp.pCV || 0) - (+inp.pPV || 0);
  const boxPct = box / s;
  const rendMax = asa - debito;
  const cl = debito / asa;
  const midC = s + box / 2 + asa / 2, midP = s - box / 2 - asa / 2;
  const resMid = asa / 2 - debito;
  const varMid = (box / 2 + asa / 2) / s, varMax = (box / 2 + asa) / s;
  return { s, box, asa, dte, kCC, kPC, kCV, kPV, hasPrices, debito, boxPct, rendMax, cl, midC, midP, resMid, varMid, varMax };
}

// expiração: 3ª sexta do mês da série, próxima ocorrência >= hoje
function expDate(serie) {
  const mi = SERIES.indexOf(serie); if (mi < 0) return null;
  const today = new Date(); today.setHours(0, 0, 0, 0);
  for (let y = today.getFullYear(); y <= today.getFullYear() + 1; y++) {
    const d = new Date(y, mi, 1); let f = (5 - d.getDay() + 7) % 7; let third = 1 + f + 14;
    const exp = new Date(y, mi, third); exp.setHours(0, 0, 0, 0);
    if (exp >= today) return exp;
  }
  return null;
}
function calDays(serie) {
  const e = expDate(serie); if (!e) return null;
  const t = new Date(); t.setHours(0, 0, 0, 0);
  return Math.round((e - t) / 86400000);
}

// ---------- atoms ----------
function Lbl({ children }) {
  return <span style={{ fontFamily: FM, fontSize: 10, letterSpacing: ".07em", textTransform: "uppercase", color: C.faint }}>{children}</span>;
}
function Field({ label, value, onChange, onBlur, suffix, step = "0.01", w, accent }) {
  return (
    <label style={{ display: "flex", flexDirection: "column", gap: 4, width: w || "auto" }}>
      <Lbl>{label}</Lbl>
      <div style={{ display: "flex", alignItems: "center", background: C.panel, border: `1px solid ${accent || C.line}`, borderRadius: 6 }}>
        <input type="number" step={step} value={value} onChange={(e) => onChange(e.target.value)} onBlur={onBlur}
          style={{ width: "100%", background: "transparent", border: "none", outline: "none", color: C.ink, fontFamily: FM, fontSize: 14, padding: "8px 10px" }} />
        {suffix && <span style={{ fontFamily: FM, fontSize: 11, color: C.faint, paddingRight: 10 }}>{suffix}</span>}
      </div>
    </label>
  );
}
function Sel({ label, value, onChange, options, w }) {
  return (
    <label style={{ display: "flex", flexDirection: "column", gap: 4, width: w || "auto" }}>
      <Lbl>{label}</Lbl>
      <select value={value} onChange={(e) => onChange(e.target.value)}
        style={{ background: C.panel, border: `1px solid ${C.line}`, borderRadius: 6, color: C.ink, fontFamily: FM, fontSize: 14, padding: "8px 10px" }}>
        {options.map((o) => <option key={o} value={o}>{o}</option>)}
      </select>
    </label>
  );
}
function Stat({ label, value, sub, col }) {
  return (
    <div style={{ background: C.panel, border: `1px solid ${C.line}`, borderRadius: 8, padding: "10px 12px" }}>
      <div style={{ fontFamily: FM, fontSize: 10, letterSpacing: ".07em", textTransform: "uppercase", color: C.faint, marginBottom: 4 }}>{label}</div>
      <div style={{ fontFamily: FM, fontSize: 19, color: col || C.ink, fontWeight: 600 }}>{value}</div>
      {sub && <div style={{ fontFamily: FM, fontSize: 11, color: C.dim, marginTop: 2 }}>{sub}</div>}
    </div>
  );
}
const hd = { fontFamily: FS, fontSize: 13, fontWeight: 600, color: C.ink, margin: "0 0 12px" };
const card = { background: C.panel2, border: `1px solid ${C.line}`, borderRadius: 12, padding: 16 };
const th = { textAlign: "right", padding: "6px 8px", color: C.faint, fontSize: 10, textTransform: "uppercase", letterSpacing: ".05em", borderBottom: `1px solid ${C.line}`, whiteSpace: "nowrap" };
const td = { textAlign: "right", padding: "6px 8px", color: C.ink, borderBottom: `1px solid ${C.line}`, whiteSpace: "nowrap" };

// ---------- diagrama (assinatura) ----------
function StructureDiagram({ r }) {
  if (!r) return null;
  const { kPV, kPC, kCC, kCV, s, midC, midP } = r;
  const W = 720, H = 150, padX = 44, y = 92;
  const span = kCV - kPV || 1, lo = kPV - span * 0.12, hi = kCV + span * 0.12;
  const X = (k) => padX + ((k - lo) / (hi - lo)) * (W - 2 * padX);
  const tick = (k, label, col, up) => (
    <g key={label + k}>
      <line x1={X(k)} y1={y - 7} x2={X(k)} y2={y + 7} stroke={col} strokeWidth="1.5" />
      <text x={X(k)} y={up ? y - 14 : y + 22} fill={col} fontFamily={FM} fontSize="10" textAnchor="middle">{label}</text>
      <text x={X(k)} y={up ? y - 26 : y + 34} fill={C.faint} fontFamily={FM} fontSize="9" textAnchor="middle">{fmt(k, 2)}</text>
    </g>
  );
  return (
    <svg viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", height: "auto" }}>
      <defs><pattern id="g" width="24" height="24" patternUnits="userSpaceOnUse"><path d="M24 0H0V24" fill="none" stroke={C.line} strokeWidth="0.5" /></pattern></defs>
      <rect x="0" y="0" width={W} height={H} fill="url(#g)" opacity="0.6" />
      <rect x={X(kPC)} y={y - 4} width={X(kCC) - X(kPC)} height="8" fill={C.gold} opacity="0.16" />
      <line x1={X(kPV)} y1={y} x2={X(kPC)} y2={y} stroke={C.clay} strokeWidth="2.5" />
      <line x1={X(kCC)} y1={y} x2={X(kCV)} y2={y} stroke={C.clay} strokeWidth="2.5" />
      <line x1={X(kPC)} y1={y} x2={X(kCC)} y2={y} stroke={C.gold} strokeWidth="2.5" />
      <line x1={X(s)} y1={y - 30} x2={X(s)} y2={y + 14} stroke={C.ink} strokeWidth="1" strokeDasharray="3 3" />
      <text x={X(s)} y={y - 36} fill={C.ink} fontFamily={FM} fontSize="10" textAnchor="middle">S {fmt(s, 2)}</text>
      {[midP, midC].map((m) => (
        <g key={m}><circle cx={X(m)} cy={y} r="4" fill={C.teal} />
          <text x={X(m)} y={y + 46} fill={C.teal} fontFamily={FM} fontSize="9" textAnchor="middle">PM {fmt(m, 2)}</text></g>
      ))}
      {tick(kPV, "put V", C.clay, false)}{tick(kPC, "put C", C.gold, true)}
      {tick(kCC, "call C", C.gold, true)}{tick(kCV, "call V", C.clay, false)}
    </svg>
  );
}

// ---------- leg input (strike em cima, preço embaixo) ----------
function LegInput({ title, strike, price, onStrike, onPrice, accent }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 6, background: C.panel, border: `1px solid ${C.line}`, borderRadius: 8, padding: 10 }}>
      <div style={{ fontFamily: FM, fontSize: 11, color: accent, fontWeight: 600, textAlign: "center" }}>{title}</div>
      <div>
        <Lbl>strike</Lbl>
        <input type="number" step="0.01" value={strike} onChange={(e) => onStrike(e.target.value)}
          style={{ width: "100%", background: C.panel2, border: `1px dashed ${C.line}`, borderRadius: 5, color: C.gold, fontFamily: FM, fontSize: 13, padding: "6px 8px", marginTop: 2 }} />
      </div>
      <div>
        <Lbl>preço</Lbl>
        <input type="number" step="0.01" value={price} onChange={(e) => onPrice(e.target.value)} placeholder="—"
          style={{ width: "100%", background: C.panel, border: `1px solid ${C.line}`, borderRadius: 5, color: C.ink, fontFamily: FM, fontSize: 13, padding: "6px 8px", marginTop: 2 }} />
      </div>
    </div>
  );
}

function TargetRow({ title, v, p, note }) {
  return (
    <div style={{ background: C.panel, border: `1px solid ${C.line}`, borderRadius: 8, padding: 12 }}>
      <div style={{ fontFamily: FM, fontSize: 11, color: C.dim, marginBottom: 6 }}>{title}</div>
      <div style={{ display: "flex", alignItems: "baseline", gap: 10 }}>
        <span style={{ fontFamily: FM, fontSize: 22, color: C.gold, fontWeight: 600 }}>{pct(v)}</span>
        <span style={{ fontFamily: FM, fontSize: 13, color: p ? C.teal : C.faint }}>{p ? `P≈${p.p}%` : "—"}</span>
      </div>
      <div style={{ fontFamily: FM, fontSize: 10, color: C.faint, marginTop: 4 }}>{note}{p && p.extr ? " · extrapolado" : ""}</div>
    </div>
  );
}

// =================== ABA NOVA OPERAÇÃO ===================
function NovaOperacao({ f, setF, onAdd, addedFlash }) {
  const set = (k) => (v) => setF((s) => ({ ...s, [k]: v }));
  const fillStrikes = useCallback(() => {
    setF((s) => {
      const S = +s.S, box = +s.box, asa = +s.asa;
      if (!(S > 0 && box > 0 && asa > 0)) return s;
      return { ...s, kCC: (S + box / 2).toFixed(2), kPC: (S - box / 2).toFixed(2), kCV: (S + box / 2 + asa).toFixed(2), kPV: (S - box / 2 - asa).toFixed(2) };
    });
  }, []);

  const r = useMemo(() => computeOp(f), [f]);
  const hist = useMemo(() => {
    if (!r) return [];
    return HIST.filter((h) => h.a === f.ativo && Math.abs(h.dte - r.dte) <= 3 && Math.abs(h.bx - r.boxPct) <= 0.012)
      .sort((a, b) => (a.dte - b.dte) || (a.bx - b.bx));
  }, [f.ativo, r]);
  const pMid = r ? pToque(f.ativo, r.varMid, r.dte) : null;
  const pMax = r ? pToque(f.ativo, r.varMax, r.dte) : null;
  const bc = r ? boxClass(r.boxPct) : null;
  const cli = r && r.hasPrices ? clInfo(r.cl) : null;

  const linha = useMemo(() => {
    if (!r) return "";
    const today = new Date().toISOString().slice(0, 10);
    const cols = new Array(45).fill("");
    cols[0] = today;          // col1 Data
    cols[2] = f.serie;        // col3 série
    cols[4] = f.ativo;        // col5 ativo
    cols[20] = f.pCC;         // col21 call comprada preço
    cols[23] = f.pCV;         // col24 call vendida preço
    cols[24] = f.pPV;         // col25 put vendida preço
    cols[27] = f.pPC;         // col28 put comprada preço
    cols[29] = (+f.S).toFixed(2); // col30 S
    cols[43] = (+f.box).toFixed(2); // col44 box R$ (Tam Box Desejado)
    cols[44] = (+f.asa).toFixed(2); // col45 asa R$ (GAP Desejado)
    return cols.join("\t");
  }, [r, f.serie, f.ativo, f.pCC, f.pCV, f.pPV, f.pPC, f.S, f.box, f.asa]);

  const [copied, setCopied] = useState(false);
  const copy = () => { navigator.clipboard?.writeText(linha); setCopied(true); setTimeout(() => setCopied(false), 1600); };
  const exp = expDate(f.serie);

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <section style={card}>
        <h3 style={hd}>Entrada</h3>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(110px,1fr))", gap: 12 }}>
          <Sel label="Ativo" value={f.ativo} onChange={set("ativo")} options={["PETR4", "VALE3", "BOVA11"]} />
          <Sel label="Série" value={f.serie} onChange={set("serie")} options={SERIES} />
          <Field label="Preço S" value={f.S} onChange={set("S")} onBlur={fillStrikes} />
          <Field label="Box (R$)" value={f.box} onChange={set("box")} onBlur={fillStrikes} />
          <Field label="Asa (R$)" value={f.asa} onChange={set("asa")} onBlur={fillStrikes} />
          <Field label="DTE (du)" value={f.dte} onChange={set("dte")} step="1" />
          <Field label="Qtd contratos" value={f.qtd} onChange={set("qtd")} step="1000" />
        </div>
        <div style={{ fontFamily: FM, fontSize: 10, color: C.faint, marginTop: 8 }}>
          Série {f.serie} = venc. {MONTHS[SERIES.indexOf(f.serie)]} (3ª sexta){exp ? ` · ${exp.toISOString().slice(0, 10)} · ${calDays(f.serie)} dias corridos` : ""}. Strikes preenchem ao sair de box/asa; editáveis para estrutura assimétrica.
        </div>
      </section>

      {r && (
        <>
          <section style={card}>
            <h3 style={hd}>Pernas — esquerda→direita = ordem do diagrama</h3>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(130px,1fr))", gap: 10, marginBottom: 14 }}>
              <LegInput title="Put vendida" strike={f.kPV} price={f.pPV} onStrike={set("kPV")} onPrice={set("pPV")} accent={C.clay} />
              <LegInput title="Put comprada" strike={f.kPC} price={f.pPC} onStrike={set("kPC")} onPrice={set("pPC")} accent={C.gold} />
              <LegInput title="Call comprada" strike={f.kCC} price={f.pCC} onStrike={set("kCC")} onPrice={set("pCC")} accent={C.gold} />
              <LegInput title="Call vendida" strike={f.kCV} price={f.pCV} onStrike={set("kCV")} onPrice={set("pCV")} accent={C.clay} />
            </div>
            <label style={{ display: "inline-flex", alignItems: "center", gap: 8, cursor: "pointer", padding: "8px 12px", borderRadius: 8, border: `2px solid ${f.callEur ? C.line : C.clay}`, background: f.callEur ? C.panel : C.clayBg }}>
              <input type="checkbox" checked={f.callEur} onChange={(e) => set("callEur")(e.target.checked)} style={{ width: 16, height: 16, accentColor: C.teal }} />
              <span style={{ fontFamily: FM, fontSize: 12, color: f.callEur ? C.dim : C.clay, fontWeight: 600 }}>
                {f.callEur ? "call vendida = europeia ✓ conferido" : "⚠ confirmar: call vendida é EUROPEIA (nunca vender americana)"}
              </span>
            </label>
            <div style={{ marginTop: 14 }}><StructureDiagram r={r} /></div>
          </section>

          <section style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(140px,1fr))", gap: 12 }}>
            <Stat label="Box %" value={pct(r.boxPct)} sub={bc.tag} col={bc.col} />
            <Stat label="Débito (custo)" value={r.hasPrices ? fmt(r.debito) : "—"} sub={r.hasPrices ? "perda máx" : "preencha os preços"} />
            <Stat label="C / L" value={r.hasPrices ? pct(r.cl, 1) : "—"} sub={cli ? cli.t : "débito ÷ asa"} col={cli ? cli.col : C.ink} />
            <Stat label="RendMax" value={r.hasPrices ? fmt(r.rendMax) : "—"} sub="asa − débito" col={C.teal} />
          </section>

          <section style={card}>
            <h3 style={hd}>Ponto médio — estimador de resultado</h3>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(150px,1fr))", gap: 12 }}>
              <Stat label="PM call / put" value={`${fmt(r.midC)} / ${fmt(r.midP)}`} sub="meio comprada↔vendida" />
              <Stat label="Result. no PM" value={r.hasPrices ? fmt(r.resMid) : "—"} sub="asa/2 − débito" col={r.hasPrices ? (r.resMid > 0 ? C.teal : C.clay) : C.ink} />
              <Stat label="Sinal" value={r.hasPrices ? (r.resMid > 0 ? "MONTA ✓" : "AJUSTAR") : "—"} sub={r.hasPrices && r.resMid <= 0 ? "calibre box/asa" : "dial de calibração"} col={r.hasPrices ? (r.resMid > 0 ? C.teal : C.clay) : C.ink} />
            </div>
          </section>

          <section style={card}>
            <h3 style={hd}>Variações-alvo · P(toque) em ≤{r.dte} du (25 anos)</h3>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
              <TargetRow title="Até o ponto médio" v={r.varMid} p={pMid} note="break-even prático" />
              <TargetRow title="Até a vendida (lucro máx)" v={r.varMax} p={pMax} note="RendMax pleno" />
            </div>
          </section>

          <section style={card}>
            <h3 style={hd}>Comparativo histórico — {f.ativo} · DTE {r.dte}±3 · box {pct(r.boxPct, 1)} ±1,2pp <span style={{ color: C.faint, fontWeight: 400 }}>({hist.length}) · ordenado por DTE, depois box</span></h3>
            {hist.length === 0 ? (
              <p style={{ fontFamily: FM, fontSize: 12, color: C.dim }}>Nenhuma operação parecida. Amplie box/DTE ou registre esta como nova referência.</p>
            ) : (
              <div style={{ overflowX: "auto" }}>
                <table style={{ width: "100%", borderCollapse: "collapse", fontFamily: FM, fontSize: 12 }}>
                  <thead><tr>{["Data", "Sér", "DTE", "Box%", "Débito", "C/L", "RendMax", "Result./contr."].map((h) => <th key={h} style={th}>{h}</th>)}</tr></thead>
                  <tbody>{hist.map((h, i) => (
                    <tr key={i}>
                      <td style={td}>{h.d}</td><td style={td}>{h.s || "—"}</td><td style={td}>{h.dte}</td><td style={td}>{pct(h.bx, 1)}</td>
                      <td style={td}>{fmt(h.db)}</td><td style={td}>{h.cl != null ? pct(h.cl, 1) : "—"}</td><td style={td}>{fmt(h.rm)}</td>
                      <td style={{ ...td, color: h.r == null ? C.faint : (h.r > 0 ? C.teal : C.clay) }}>{h.r == null ? "— (só digitada)" : fmt(h.r, 3)}</td>
                    </tr>))}</tbody>
                </table>
              </div>
            )}
          </section>

          <section style={card}>
            <h3 style={hd}>Registrar — linha na ordem exata da aba Main (col 1→30)</h3>
            <div style={{ display: "flex", gap: 10, alignItems: "stretch", flexWrap: "wrap" }}>
              <code style={{ flex: 1, minWidth: 240, background: C.panel, border: `1px solid ${C.line}`, borderRadius: 6, padding: "10px 12px", fontFamily: FM, fontSize: 11, color: C.dim, overflowX: "auto", whiteSpace: "nowrap" }}>{linha}</code>
              <button onClick={copy} style={{ background: copied ? C.teal : C.gold, color: "#fff", border: "none", borderRadius: 6, padding: "0 18px", fontFamily: FS, fontWeight: 600, fontSize: 13, cursor: "pointer" }}>{copied ? "Copiado ✓" : "Copiar"}</button>
            </div>
            <p style={{ fontFamily: FM, fontSize: 10, color: C.faint, marginTop: 8 }}>Só os campos de ENTRADA (Data·série·ativo·4 preços·S·box R$·asa R$); as colunas-fórmula vão em branco. Cole em A{"{linha}"} com <b>colar especial → pular vazios</b> para preservar as fórmulas.</p>
          </section>

          <section style={{ ...card, display: "flex", alignItems: "center", justifyContent: "space-between", flexWrap: "wrap", gap: 12 }}>
            <div>
              <div style={{ fontFamily: FS, fontSize: 13, fontWeight: 600 }}>Comparar esta montagem</div>
              <div style={{ fontFamily: FM, fontSize: 11, color: C.dim }}>adiciona à lista na aba Comparador; volte e monte outra variação</div>
            </div>
            <button onClick={() => onAdd({ ...r, ativo: f.ativo, serie: f.serie })} disabled={!r}
              style={{ background: addedFlash ? C.teal : C.blue, color: "#fff", border: "none", borderRadius: 6, padding: "10px 18px", fontFamily: FS, fontWeight: 600, fontSize: 13, cursor: "pointer" }}>
              {addedFlash ? "Adicionada ✓" : "+ adicionar à lista"}
            </button>
          </section>
        </>
      )}
    </div>
  );
}

// =================== ABA COMPARADOR ===================
function Comparador({ list, onClear, onRemove }) {
  const ativos = [...new Set(list.map((o) => o.ativo))];
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <section style={card}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12, flexWrap: "wrap", gap: 8 }}>
          <h3 style={{ ...hd, margin: 0 }}>Comparação ({list.length}){ativos.length > 1 ? <span style={{ color: C.clay, fontWeight: 400, fontSize: 11 }}> · atenção: ativos diferentes ({ativos.join(", ")})</span> : ativos.length === 1 ? <span style={{ color: C.faint, fontWeight: 400, fontSize: 11 }}> · {ativos[0]}</span> : null}</h3>
          {list.length > 0 && <button onClick={onClear} style={{ background: "transparent", color: C.clay, border: `1px solid ${C.clay}`, borderRadius: 6, padding: "5px 12px", fontFamily: FS, fontSize: 12, cursor: "pointer" }}>limpar lista</button>}
        </div>
        {list.length === 0 ? (
          <p style={{ fontFamily: FM, fontSize: 12, color: C.dim }}>Vazio. Na aba <b>Nova operação</b>, monte uma variação e clique <b>+ adicionar à lista</b>. Volte, mude box/asa, adicione outra — e compare aqui qual montar.</p>
        ) : (
          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", borderCollapse: "collapse", fontFamily: FM, fontSize: 12 }}>
              <thead><tr>{["#", "Ativo", "Sér", "Box%", "Asa", "DTE", "Débito", "C/L", "RendMax", "PM call", "var→PM", "P", "var→máx", "P", "res PM", ""].map((h, i) => <th key={i} style={th}>{h}</th>)}</tr></thead>
              <tbody>{list.map((o, i) => (
                <tr key={i}>
                  <td style={td}>{i + 1}</td><td style={td}>{o.ativo}</td><td style={td}>{o.serie}</td><td style={td}>{pct(o.boxPct, 1)}</td><td style={td}>{fmt(o.asa, 1)}</td><td style={td}>{o.dte}</td>
                  <td style={td}>{o.hasPrices ? fmt(o.debito) : "—"}</td>
                  <td style={{ ...td, color: o.hasPrices ? clInfo(o.cl).col : C.ink }}>{o.hasPrices ? pct(o.cl, 1) : "—"}</td>
                  <td style={td}>{o.hasPrices ? fmt(o.rendMax) : "—"}</td><td style={td}>{fmt(o.midC)}</td>
                  <td style={td}>{pct(o.varMid, 1)}</td><td style={{ ...td, color: C.teal }}>{o.pMid ? o.pMid.p + "%" : "—"}</td>
                  <td style={td}>{pct(o.varMax, 1)}</td><td style={{ ...td, color: C.teal }}>{o.pMax ? o.pMax.p + "%" : "—"}</td>
                  <td style={{ ...td, color: o.hasPrices ? (o.resMid > 0 ? C.teal : C.clay) : C.ink }}>{o.hasPrices ? fmt(o.resMid) : "—"}</td>
                  <td style={td}><button onClick={() => onRemove(i)} style={{ background: "transparent", color: C.clay, border: "none", cursor: "pointer", fontFamily: FM, fontSize: 16 }}>×</button></td>
                </tr>))}</tbody>
            </table>
          </div>
        )}
      </section>
    </div>
  );
}

// =================== ABA VOLATILIDADE ===================
function StraddleChart({ ativo, rows, today }) {
  const curve = STR[ativo] || {};
  const dtes = Object.keys(curve).map(Number).sort((a, b) => a - b);
  if (!dtes.length) return null;
  const W = 920, H = 400, padL = 56, padR = 20, padT = 34, padB = 38;
  const xmin = 0, xmax = 45;
  const cur = rows.filter((r) => r.dte !== "" && r.straddle && r.S);
  const curRatios = cur.map((r) => +r.straddle / +r.S);
  const has25 = dtes.some((d) => curve[d].m25 != null);
  const allR = dtes.flatMap((d) => [curve[d].q1, curve[d].q3].concat(curve[d].m25 != null ? [curve[d].m25] : [])).concat(curRatios);
  if (today) allR.push(today.ratio);
  const ymax = Math.max(...allR) * 1.08, ymin = Math.min(...allR) * 0.9;
  const X = (dte) => padL + ((xmax - dte) / (xmax - xmin)) * (W - padL - padR);
  const Y = (v) => padT + (1 - (v - ymin) / (ymax - ymin)) * (H - padT - padB);
  const line = (key) => { const ds = dtes.filter((d) => curve[d][key] != null); return ds.map((d, i) => `${i ? "L" : "M"}${X(d).toFixed(1)} ${Y(curve[d][key]).toFixed(1)}`).join(" "); };
  const up = dtes.map((d, i) => `${i ? "L" : "M"}${X(d).toFixed(1)} ${Y(curve[d].q3).toFixed(1)}`).join(" ");
  const dn = [...dtes].reverse().map((d) => `L${X(d).toFixed(1)} ${Y(curve[d].q1).toFixed(1)}`).join(" ");
  const band = up + dn + "Z";
  const bySerie = {};
  cur.forEach((r) => { (bySerie[r.serie || "?"] = bySerie[r.serie || "?"] || []).push({ x: X(+r.dte), y: Y(+r.straddle / +r.S), dte: +r.dte }); });
  const COL = { band: "rgba(47,98,143,0.14)", q1q3: "#8FB0CC", med: "#2F628F", y25: "#197E6E", cur: "#B26A00", today: "#BC3F22" };
  const yt = 5;
  return (
    <svg viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", height: "auto", display: "block" }}>
      {Array.from({ length: yt + 1 }).map((_, i) => { const v = ymin + (i / yt) * (ymax - ymin); const yy = Y(v);
        return <g key={i}><line x1={padL} y1={yy} x2={W - padR} y2={yy} stroke={C.line} strokeWidth="0.5" />
          <text x={padL - 6} y={yy + 3} fill={C.faint} fontFamily={FM} fontSize="10" textAnchor="end">{(v * 100).toFixed(1)}%</text></g>; })}
      {[45, 40, 35, 30, 25, 20, 15, 10, 6, 0].map((d) => <text key={d} x={X(d)} y={H - padB + 18} fill={C.faint} fontFamily={FM} fontSize="10" textAnchor="middle">{d}</text>)}
      <text x={W / 2} y={H - 4} fill={C.dim} fontFamily={FM} fontSize="10" textAnchor="middle">DTE (45 → 0) · eixo Y = ratio straddle ÷ S</text>
      <path d={band} fill={COL.band} stroke="none" />
      <path d={line("q1")} fill="none" stroke={COL.q1q3} strokeWidth="1" strokeDasharray="2 3" />
      <path d={line("q3")} fill="none" stroke={COL.q1q3} strokeWidth="1" strokeDasharray="2 3" />
      <path d={line("q2")} fill="none" stroke={COL.med} strokeWidth="2" />
      {has25 && <path d={line("m25")} fill="none" stroke={COL.y25} strokeWidth="2.2" />}
      {Object.values(bySerie).map((pts, k) => {
        const sorted = pts.sort((a, b) => b.dte - a.dte);
        const p = sorted.map((q, i) => `${i ? "L" : "M"}${q.x.toFixed(1)} ${q.y.toFixed(1)}`).join(" ");
        return <g key={k}><path d={p} fill="none" stroke={COL.cur} strokeWidth="2.6" />{sorted.map((q, i) => <circle key={i} cx={q.x} cy={q.y} r="4.5" fill={COL.cur} />)}</g>;
      })}
      {today && <g><circle cx={X(today.dte)} cy={Y(today.ratio)} r="7" fill="none" stroke={COL.today} strokeWidth="2.5" />
        <text x={X(today.dte)} y={Y(today.ratio) - 12} fill={COL.today} fontFamily={FM} fontSize="11" textAnchor="middle" fontWeight="600">hoje</text></g>}
      <g fontFamily={FM} fontSize="10">
        <rect x={padL + 6} y={padT - 22} width="14" height="9" fill={COL.band} stroke={COL.q1q3} strokeWidth="0.5" /><text x={padL + 25} y={padT - 14} fill={C.dim}>Q1–Q3 (faixa)</text>
        <line x1={padL + 118} y1={padT - 17} x2={padL + 134} y2={padT - 17} stroke={COL.med} strokeWidth="2" /><text x={padL + 139} y={padT - 14} fill={C.dim}>mediana (Q2)</text>
        <line x1={padL + 232} y1={padT - 17} x2={padL + 248} y2={padT - 17} stroke={COL.y25} strokeWidth="2.2" /><text x={padL + 253} y={padT - 14} fill={C.dim}>2025 ★</text>
        <line x1={padL + 308} y1={padT - 17} x2={padL + 324} y2={padT - 17} stroke={COL.cur} strokeWidth="2.6" /><text x={padL + 329} y={padT - 14} fill={C.dim}>série atual</text>
      </g>
    </svg>
  );
}

function VolTab() {
  const [ativo, setAtivo] = useState("VALE3");
  const [serie, setSerie] = useState("F");
  const [S, setS] = useState("77.33");
  const [dte, setDte] = useState("26");
  const [call, setCall] = useState("");
  const [put, setPut] = useState("");
  const [vxbr, setVxbr] = useState("");
  const seedRows = (a) => { const s = (SEED[a] || []).map((x) => ({ dte: String(x.dte), serie: x.serie, straddle: String(x.straddle), S: String(x.S) })); while (s.length < 8) s.push({ dte: "", serie: "", straddle: "", S: "" }); return s; };
  const [rows, setRows] = useState(() => seedRows("VALE3"));
  useEffect(() => { setRows(seedRows(ativo)); }, [ativo]);
  const setRow = (i, k, v) => setRows((r) => r.map((x, j) => (j === i ? { ...x, [k]: v } : x)));

  const iv = useMemo(() => { const s = +S, d = parseInt(dte), c = +call, p = +put; if (!(s > 0 && d > 0 && c >= 0 && p >= 0 && c + p > 0)) return null; return (c + p) / (0.8 * s * Math.sqrt(d / 252)); }, [S, dte, call, put]);
  const win = IVWIN[ativo] || {};
  const percentileIn = (arr) => { if (!arr || iv == null) return null; let b = 0; arr.forEach((q) => { if (iv >= q) b++; }); return Math.round((b / arr.length) * 100 / 5) * 5; };
  const wins = [["d90", "90d"], ["d180", "180d"], ["d365", "365d"], ["all", "hist"]];
  const vy = VOLYR[ativo] || {}; const anos = Object.keys(vy).sort();
  const vxN = +vxbr; const vxReg = isNaN(vxN) || vxbr === "" ? null : (vxN < 16 ? { t: "baixa", c: C.teal } : vxN <= 22 ? { t: "normal", c: C.gold } : { t: "elevada", c: C.clay });
  const curve = STR[ativo] || {};
  const todayStr = (+call || 0) + (+put || 0);
  const todayRatio = todayStr > 0 && +S > 0 ? todayStr / +S : null;
  const todayPt = todayRatio != null && +dte >= 0 && +dte <= 45 ? { dte: +dte, ratio: todayRatio } : null;
  const cAt = curve[Math.round(+dte)];

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <section style={card}>
        <h3 style={hd}>IV caseira — straddle ATM</h3>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(95px,1fr))", gap: 10 }}>
          <Sel label="Ativo" value={ativo} onChange={setAtivo} options={["PETR4", "VALE3", "BOVA11"]} />
          <Sel label="Série" value={serie} onChange={setSerie} options={SERIES} />
          <Field label="Preço S" value={S} onChange={setS} />
          <Field label="DTE" value={dte} onChange={setDte} step="1" />
          <Field label="Call ATM" value={call} onChange={setCall} />
          <Field label="Put ATM" value={put} onChange={setPut} />
        </div>
      </section>

      {iv != null && (
        <section style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(120px,1fr))", gap: 12 }}>
          <Stat label="IV caseira atual" value={pct(iv, 1)} sub={`straddle ${fmt(todayStr)} · DTE ${dte}`} col={C.gold} />
          {wins.map(([k, lbl]) => { const w = win[k]; const p = w && w.p ? percentileIn(w.p) : null; const col = p == null ? C.ink : p < 40 ? C.teal : p <= 60 ? C.gold : C.clay; return <Stat key={k} label={`percentil ${lbl}`} value={p == null ? "—" : "p" + p} sub={w ? `n=${w.n}` : ""} col={col} />; })}
        </section>
      )}

      <section style={card}>
        <h3 style={hd}>VXBR — regime de mercado</h3>
        <div style={{ display: "flex", gap: 14, alignItems: "flex-end", flexWrap: "wrap" }}>
          <Field label="VXBR atual" value={vxbr} onChange={setVxbr} step="0.1" w="130px" />
          {vxReg && <div style={{ fontFamily: FM, fontSize: 14, color: vxReg.c, paddingBottom: 8, fontWeight: 600 }}>regime {vxReg.t}</div>}
          <p style={{ fontFamily: FM, fontSize: 10, color: C.faint, paddingBottom: 8, flex: 1, minWidth: 200 }}>&lt;16 baixa · 16–22 normal · &gt;22 elevada. Peça a análise e eu busco no Investing.com. BOVA11 ≈ VXBR direto.</p>
        </div>
      </section>

      <section style={card}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4, flexWrap: "wrap", gap: 8 }}>
          <h3 style={{ ...hd, margin: 0 }}>Straddle da série · ratio vs faixa histórica (quartis) e 2025</h3>
        </div>
        <p style={{ fontFamily: FM, fontSize: 10, color: C.faint, margin: "0 0 12px" }}>Fonte: planilha VI RF (abas Ratio e Series atuais, vivas). Faixa Q1–Q3 = straddle "normal" por DTE; mediana e 2025 ★ como âncoras. A série atual já vem carregada; edite à mão se quiser. Queda forte (15–20c) tende a estabilizar → bom dia de montar.</p>

        <div style={{ overflowX: "auto", marginBottom: 16 }}>
          <table style={{ borderCollapse: "collapse", fontFamily: FM, fontSize: 11 }}>
            <thead><tr>{["DTE", "Série", "straddle", "S", "ratio", "mediana Q2", "2025 ★"].map((h) => <th key={h} style={{ ...th, padding: "4px 8px" }}>{h}</th>)}</tr></thead>
            <tbody>{rows.map((rw, i) => {
              const c = rw.dte !== "" && curve[Math.round(+rw.dte)] ? curve[Math.round(+rw.dte)] : null;
              const ratio = rw.straddle && rw.S ? +rw.straddle / +rw.S : null;
              return (
                <tr key={i}>
                  {[["dte", 46], ["serie", 46], ["straddle", 70], ["S", 70]].map(([k, w]) => (
                    <td key={k} style={{ padding: "2px 4px", borderBottom: `1px solid ${C.line}` }}>
                      <input type={k === "serie" ? "text" : "number"} value={rw[k]} onChange={(e) => setRow(i, k, e.target.value)} placeholder="—"
                        style={{ width: w, background: C.panel, border: `1px solid ${C.line}`, borderRadius: 4, color: C.ink, fontFamily: FM, fontSize: 11, padding: "4px 6px" }} />
                    </td>
                  ))}
                  <td style={{ ...td, padding: "4px 8px", color: C.gold }}>{ratio != null ? (ratio * 100).toFixed(2) + "%" : "—"}</td>
                  <td style={{ ...td, padding: "4px 8px", color: C.blue }}>{c ? (c.q2 * 100).toFixed(2) + "%" : "—"}</td>
                  <td style={{ ...td, padding: "4px 8px", color: C.teal }}>{c && c.m25 != null ? (c.m25 * 100).toFixed(2) + "%" : "—"}</td>
                </tr>
              );
            })}</tbody>
          </table>
        </div>

        <StraddleChart ativo={ativo} rows={rows} today={todayPt} />

        {todayRatio != null && (
          <p style={{ fontFamily: FM, fontSize: 11, color: C.dim, marginTop: 10 }}>
            Hoje (DTE {dte}): ratio {(todayRatio * 100).toFixed(2)}%
            {cAt ? ` · faixa Q1–Q3 ${(cAt.q1 * 100).toFixed(2)}–${(cAt.q3 * 100).toFixed(2)}% · mediana ${(cAt.q2 * 100).toFixed(2)}%${cAt.m25 != null ? ` · 2025 ★ ${(cAt.m25 * 100).toFixed(2)}%` : ""}` : ""}
          </p>
        )}
      </section>

      <section style={card}>
        <h3 style={hd}>Vol caseira por ano — {ativo} <span style={{ color: C.faint, fontWeight: 400 }}>· 2025 = cenário favorável de referência</span></h3>
        {iv != null && (
          <div style={{ background: C.goldBg, border: `1px solid ${C.gold}`, borderRadius: 8, padding: "8px 12px", marginBottom: 12, fontFamily: FM, fontSize: 12, color: C.ink }}>
            σ caseira <b>atual</b> (DTE {dte}): <span style={{ color: C.gold, fontWeight: 600 }}>{pct(iv, 1)}</span> — compare com as medianas anuais (2025 ★ {vy["2025"] ? pct(vy["2025"].mediana, 1) : "—"}).
          </div>
        )}
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontFamily: FM, fontSize: 12 }}>
            <thead><tr>{["Ano", "n", "Topo", "Base", "Média", "Mediana"].map((h) => <th key={h} style={th}>{h}</th>)}</tr></thead>
            <tbody>{anos.map((y) => { const dd = vy[y]; const is = y === "2025"; return (
              <tr key={y} style={{ background: is ? C.tealBg : "transparent" }}>
                <td style={{ ...td, color: is ? C.teal : C.ink }}>{y}{is ? " ★" : ""}</td>
                <td style={td}>{dd.n}</td><td style={td}>{fmt(dd.topo, 3)}</td><td style={td}>{fmt(dd.base, 3)}</td>
                <td style={td}>{fmt(dd.media, 3)}</td><td style={{ ...td, color: is ? C.teal : C.ink }}>{fmt(dd.mediana, 3)}</td>
              </tr>); })}</tbody>
          </table>
        </div>
        <p style={{ fontFamily: FM, fontSize: 10, color: C.faint, marginTop: 8 }}>σ ≈ straddle ÷ (0,8·S·√(du/252)). Teto: montar com IV do nome &lt; ~p60 da janela 365d.</p>
      </section>
    </div>
  );
}

export default function App() {
  const [tab, setTab] = useState("nova");
  const [novaForm, setNovaForm] = useState({
    ativo: "VALE3", serie: "F", S: "80", box: "6.4", asa: "3", dte: "27",
    kPV: "", kPC: "", kCC: "", kCV: "", pPV: "", pPC: "", pCC: "", pCV: "",
    qtd: "30000", callEur: false,
  });
  const [list, setList] = useState([]);
  const [flash, setFlash] = useState(false);
  const addToList = (op) => {
    const pM = pToque(op.ativo, op.varMid, op.dte), pX = pToque(op.ativo, op.varMax, op.dte);
    setList((l) => [...l, { ...op, pMid: pM, pMax: pX }]);
    setFlash(true); setTimeout(() => setFlash(false), 1500);
  };
  const tabs = [["nova", "Nova operação"], ["comp", `Comparador${list.length ? " (" + list.length + ")" : ""}`], ["vol", "Volatilidade"]];
  return (
    <div style={{ minHeight: "100vh", background: C.bg, color: C.ink, fontFamily: FS, padding: "24px 18px" }}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600&display=swap');
        *{box-sizing:border-box;} input::-webkit-outer-spin-button,input::-webkit-inner-spin-button{-webkit-appearance:none;margin:0;} input[type=number]{-moz-appearance:textfield;}`}</style>
      <div style={{ maxWidth: 920, margin: "0 auto" }}>
        <header style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between", marginBottom: 18, flexWrap: "wrap", gap: 8 }}>
          <div>
            <div style={{ fontFamily: FS, fontSize: 22, fontWeight: 700 }}>MPRf <span style={{ color: C.gold }}>·</span> montagem</div>
            <div style={{ fontFamily: FM, fontSize: 11, color: C.faint }}>condor comprado · B3 · apoio à decisão</div>
          </div>
          <div style={{ display: "flex", gap: 6, background: C.panel2, border: `1px solid ${C.line}`, borderRadius: 8, padding: 4 }}>
            {tabs.map(([k, l]) => (
              <button key={k} onClick={() => setTab(k)} style={{ background: tab === k ? C.gold : "transparent", color: tab === k ? "#fff" : C.dim, border: "none", borderRadius: 6, padding: "7px 14px", fontFamily: FS, fontWeight: 600, fontSize: 12, cursor: "pointer" }}>{l}</button>
            ))}
          </div>
        </header>
        <div style={{ display: tab === "nova" ? "block" : "none" }}><NovaOperacao f={novaForm} setF={setNovaForm} onAdd={addToList} addedFlash={flash} /></div>
        <div style={{ display: tab === "comp" ? "block" : "none" }}><Comparador list={list} onClear={() => setList([])} onRemove={(i) => setList((l) => l.filter((_, j) => j !== i))} /></div>
        <div style={{ display: tab === "vol" ? "block" : "none" }}><VolTab /></div>
        <footer style={{ fontFamily: FM, fontSize: 10, color: C.faint, marginTop: 24, textAlign: "center" }}>
          Estimativas de apoio. Saída no toque (incondicional) · stop de tempo D-6 · stop de valor 50% · vol baixa é o regime favorável.
        </footer>
      </div>
    </div>
  );
}
